{
  "sentences": [
    {
      "text": "我每天中午吃午餐。",
      "pinyin": "Wǒ měitiān zhōngwǔ chī wǔcān.",
      "pinyin_numeric": "wo3 mei3tian1 zhong1wu3 chi1 wu3can1",
      "translation_en": "I eat lunch every day at noon.",
      "translation_ko": "저는 매일 점심에 점심을 먹습니다."
    },
    {
      "text": "他每天晚上看電視。",
      "pinyin": "Tā měitiān wǎnshàng kàn diànshì.",
      "pinyin_numeric": "ta1 mei3tian1 wan3shang4 kan4 dian4shi4",
      "translation_en": "He watches TV every evening.",
      "translation_ko": "그는 매일 저녁에 텔레비전을 봅니다."
    },
    {
      "text": "我們每天上午上班。",
      "pinyin": "Wǒmen měitiān shàngwǔ shàngbān.",
      "pinyin_numeric": "wo3men mei3tian1 shang4wu3 shang4ban1",
      "translation_en": "We go to work every morning.",
      "translation_ko": "우리는 매일 오전에 출근합니다."
    },
    {
      "text": "她每天下午上課。",
      "pinyin": "Tā měitiān xiàwǔ shàngkè.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 shang4ke4",
      "translation_en": "She goes to class every afternoon.",
      "translation_ko": "그녀는 매일 오후에 수업을 듣습니다."
    },
    {
      "text": "我每天早上刷牙洗臉。",
      "pinyin": "Wǒ měitiān zǎoshàng shuāyá xǐliǎn.",
      "pinyin_numeric": "wo3 mei3tian1 zao3shang4 shua1ya2 xi3lian3",
      "translation_en": "I brush my teeth and wash my face every morning.",
      "translation_ko": "저는 매일 아침에 이를 닦고 세수합니다."
    },
    {
      "text": "他每天下班以後散步。",
      "pinyin": "Tā měitiān xiàbān yǐhòu sànbù.",
      "pinyin_numeric": "ta1 mei3tian1 xia4ban1 yi3hou4 san4bu4",
      "translation_en": "He takes a walk after work every day.",
      "translation_ko": "그는 매일 퇴근 후에 산책합니다."
    },
    {
      "text": "我們每天晚上做功課。",
      "pinyin": "Wǒmen měitiān wǎnshàng zuò gōngkè.",
      "pinyin_numeric": "wo3men mei3tian1 wan3shang4 zuo4 gong1ke4",
      "translation_en": "We do homework every evening.",
      "translation_ko": "우리는 매일 저녁에 숙제를 합니다."
    },
    {
      "text": "她每天中午休息。",
      "pinyin": "Tā měitiān zhōngwǔ xiūxí.",
      "pinyin_numeric": "ta1 mei3tian1 zhong1wu3 xiu1xi2",
      "translation_en": "She rests every day at noon.",
      "translation_ko": "그녀는 매일 점심에 휴식합니다."
    },
    {
      "text": "我每天吃早餐以前刷牙。",
      "pinyin": "Wǒ měitiān chī zǎocān yǐqián shuāyá.",
      "pinyin_numeric": "wo3 mei3tian1 chi1 zao3can1 yi3qian2 shua1ya2",
      "translation_en": "I brush my teeth before eating breakfast every day.",
      "translation_ko": "저는 매일 아침 식사 전에 이를 닦습니다."
    },
    {
      "text": "他每天回家以後看書。",
      "pinyin": "Tā měitiān huíjiā yǐhòu kànshū.",
      "pinyin_numeric": "ta1 mei3tian1 hui2jia1 yi3hou4 kan4shu1",
      "translation_en": "He reads books after going home every day.",
      "translation_ko": "그는 매일 집에 돌아온 후에 책을 읽습니다."
    }
  ]
}
